119→            </Box>
120→          )}
121→          ListEmptyComponent={() => (
122→            <Box align="center" pd="innerLarger" justify="center" mt="larger">
123→              <Image
124→                resizeMode="contain"
125→                /* @ts-ignore `source` is not in the props Of `image` ( ͡° ͜ʖ ͡°) */
126→                source={{ uri: emptyImage }}
127→                width={80}
