  1→import {
  2→  AppliedFilters,
  3→  PointsTransaction,
  4→  TransactionType,
  5→  TYPE_LABELS,
  6→} from '../../services';
  7→
  8→function getTransactionDescription(type: TransactionType): string {
  9→  return TYPE_LABELS[type] || '';
 10→}
 11→
 12→function matchesPeriodFilter(
 13→  transactionDate: Date,
 14→  periodStart: Date | null,
 15→  todayEnd: Date,
 16→): boolean {
 17→  if (!periodStart) return true;
 18→  return transactionDate >= periodStart && transactionDate <= todayEnd;
 19→}
 20→
 21→function matchesTypeFilter(
 22→  transactionType: string,
 23→  typesSet: Set<string> | null,
 24→): boolean {
 25→  if (!typesSet) return true;
 26→  return typesSet.has(transactionType.toUpperCase());
 27→}
 28→
 29→export function getFilteredTransactions(
 30→  transactions: PointsTransaction[],
 31→  filters?: AppliedFilters,
 32→): PointsTransaction[] {
 33→  const hasFilters =
 34→    filters &&
 35→    (filters.period ||
 36→      (filters.types && filters.types.length > 0) ||
 37→      filters.order);
 38→
 39→  if (!hasFilters) {
 40→    return transactions;
 41→  }
 42→
 43→  const now = new Date();
 44→  const todayEnd = new Date(now);
 45→  todayEnd.setHours(23, 59, 59, 999);
 46→
 47→  const periodStart = filters.period
 48→    ? (() => {
 49→        const date = new Date(now);
 50→        date.setDate(date.getDate() - filters.period);
 51→        date.setHours(0, 0, 0, 0);
 52→        return date;
 53→      })()
 54→    : null;
 55→
 56→  const hasTypeFilter = filters.types && filters.types.length > 0;
 57→  const typesSet = hasTypeFilter
 58→    ? new Set(filters.types!.map(type => type.toUpperCase()))
 59→    : null;
 60→
 61→  const filtered = transactions.filter(transaction => {
 62→    const transactionDate = new Date(transaction.date);
 63→
 64→    if (!matchesPeriodFilter(transactionDate, periodStart, todayEnd)) {
 65→      return false;
 66→    }
 67→
 68→    if (!matchesTypeFilter(transaction.type, typesSet)) {
 69→      return false;
 70→    }
 71→
 72→    return true;
 73→  });
 74→
 75→  if (filters.order === 'DESC') {
 76→    return [...filtered].reverse();
 77→  }
 78→
 79→  return filtered;
 80→}
 81→
 82→function matchesSearchText(
 83→  transaction: PointsTransaction,
 84→  normalizedSearch: string,
 85→  isExpiringTab: boolean,
 86→): boolean {
 87→  const amountStr = String(transaction.amount);
 88→
 89→  if (amountStr.includes(normalizedSearch)) {
 90→    return true;
 91→  }
 92→
 93→  if (isExpiringTab) {
 94→    return false;
 95→  }
 96→
 97→  const description = getTransactionDescription(transaction.type).toLowerCase();
 98→  if (description.includes(normalizedSearch)) {
 99→    return true;
100→  }
101→
102→  if (transaction.description?.toLowerCase().includes(normalizedSearch)) {
103→    return true;
104→  }
105→
106→  return false;
107→}
108→
109→export function getFilteredTransactionsByText(
110→  transactions: PointsTransaction[],
111→  searchText: string,
112→  isExpiringTab = false,
113→): PointsTransaction[] {
114→  if (!searchText?.trim() || !transactions?.length) {
115→    return transactions;
116→  }
117→
118→  const normalizedSearch = searchText.toLowerCase().trim();
119→
120→  return transactions.filter(transaction =>
121→    matchesSearchText(transaction, normalizedSearch, isExpiringTab));
122→}
