30→export type RewardsProgramRootStore = ParameterPointsProgramSlice &
31→  PermissionSlice &
32→  AirlineMilesSlice &
33→  PointsExtractSlice &
34→  PointsProductsSlice &
35→  RescueSlice &
36→  MarketplaceSlice &
37→  OrderDetailSlice;
38→
39→type Slice<T> = StateCreator<RewardsProgramRootStore, [], [], T>;
40→const asSlice = <T>(slice: StateCreator<RewardsProgramRootStore, [], [], T>) =>
41→  slice as Slice<T>;
42→
43→export function setRewardsProgramSlices<T extends RewardsProgramRootStore>(
44→  ...a: Parameters<Slice<T>>
45→) {
46→  return {
47→    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(
48→      ...a,
49→    ),
50→    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
51→    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
52→    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
53→    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
54→    ...asSlice<RescueSlice>(createRescueSlice)(...a),
55→    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
56→    ...asSlice<OrderDetailSlice>(createOrderDetailSlice)(...a),
57→  };
58→}
