  1→import { useFocusEffect, useNavigation } from '@react-navigation/native';
  2→import type { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
  3→import React, { useCallback, useMemo, useRef } from 'react';
  4→import { Dimensions } from 'react-native';
  5→import { useShallow } from 'zustand/react/shallow';
  6→import {
  7→  eventModalView,
  8→  eventScreenViewV3,
  9→  eventSelectContent,
 10→} from '~/constants/functions';
 11→import { useRootStore } from '~/store';
 12→import type { ScreenProps } from '../../routes/Models';
 13→import { OrderDetailStatus, type TransactionType } from '../../services/models';
 14→import { moment } from '../../services/moment';
 15→import { getOrderDetail } from '../../services/services';
 16→import { formatToCurrency } from '../../utils/functions';
 17→import type { MarketplaceContentData, MarketplaceItemData } from './Models';
 18→import { STATUS_COLORS } from './Models';
 19→import {
 20→  getCleanedImageUrl,
 21→  getFormattedHighlightText,
 22→  getFormattedPointsValue,
 23→  getFormattedPointsValueForMarketplace,
 24→  getMarketplaceTitle,
 25→  getPaymentTypeLabel,
 26→  getTransactionGainType,
 27→} from './utils';
 28→import MyOrdersDetailView from './view';
 29→
 30→const MyOrdersDetails = ({ route }: ScreenProps<'MyOrdersDetails'>) => {
 31→  const navigation = useNavigation();
 32→  const hasFocused = useRef(false);
 33→  const modalizeRef = useRef<PropsModalizeRef>(null);
 34→  const modalizeRefInfo = useRef<PropsModalizeRef>(null);
 35→
 36→  const { orderDetail, orderDetailActions } = useRootStore(
 37→    useShallow(state => ({
 38→      orderDetail: state.orderDetail,
 39→      orderDetailActions: state.orderDetailActions,
 40→    })),
 41→  );
 42→
 43→  const transactionId = route.params?.transactionId;
 44→  const passedType = route.params?.type;
 45→  const passedIcon = route.params?.icon;
 46→  const passedStatus = route.params?.status;
 47→  const passedOrigination = route.params?.origination;
 48→
 49→  useFocusEffect(
 50→    useCallback(() => {
 51→      if (!hasFocused.current) {
 52→        eventScreenViewV3(
 53→          'detalhe_pedido',
 54→          'hub_recompensas_spmais',
 55→          'monetizacao',
 56→          {
 57→            location_1: 'monetizacao',
 58→            location_2: 'hub_recompensas_spmais',
 59→            location_3: 'detalhe_pedido',
 60→          },
 61→        );
 62→        hasFocused.current = true;
 63→      }
 64→
 65→      if (transactionId) {
 66→        orderDetailActions.reset();
 67→        getOrderDetail({ transactionId });
 68→      }
 69→
 70→      return () => {
 71→        hasFocused.current = false;
 72→        orderDetailActions.reset();
 73→      };
 74→    }, [
 75→      transactionId,
 76→      orderDetailActions,
 77→    ]),
 78→  );
 79→
 80→  const handleGoBack = () => {
 81→    navigation.goBack();
 82→  };
 83→
 84→  const handleOpenReportProblem = () => {
 85→    eventSelectContent({
 86→      content_type: 'cta',
 87→      content_id: 'relatar_problema',
 88→      location_1: 'monetizacao',
 89→      location_2: 'hub_recompensas_spmais',
 90→      location_3: 'detalhe_pedido',
 91→    });
 92→
 93→    eventModalView({
 94→      content_id: 'contato_telefones',
 95→      location_1: 'monetizacao',
 96→      location_2: 'hub_recompensas_spmais',
 97→      location_3: 'detalhe_pedido',
 98→    });
 99→
100→    modalizeRef.current?.open?.();
101→  };
102→
103→  const handleCloseReportProblem = () => {
104→    modalizeRef.current?.close?.();
105→  };
106→
107→  const handleOpenInfo = () => {
108→    modalizeRefInfo.current?.open?.();
109→  };
110→
111→  const handleCloseInfo = () => {
112→    modalizeRefInfo.current?.close?.();
113→  };
114→
115→  const isLoading = orderDetail.status === OrderDetailStatus.LOADING;
116→  const hasError = orderDetail.status === OrderDetailStatus.ERROR;
117→  const { height } = Dimensions.get('window');
118→
119→  const handleRetry = () => {
120→    if (transactionId) {
121→      getOrderDetail({ transactionId });
122→    }
123→  };
124→
125→  const transaction = orderDetail.orderDetail;
126→
127→  const isValidTransactionType = (
128→    type: string | undefined,
129→  ): type is TransactionType => {
130→    return (
131→      type === 'CREDIT' ||
132→      type === 'RESCUE' ||
133→      type === 'EXPIRED' ||
134→      type === 'REFUNDED'
135→    );
136→  };
137→
138→  const enrichedTransaction = transaction
139→    ? {
140→        ...transaction,
141→        type: isValidTransactionType(passedType)
142→          ? passedType
143→          : transaction.type,
144→        icon: passedIcon || transaction.icon,
145→        status: passedStatus || transaction.status,
146→        details: {
147→          ...transaction.details,
148→          provider: passedOrigination || transaction.details?.provider || '',
149→        },
150→      }
151→    : undefined;
152→
153→  const isCashback = passedType === 'RESCUE';
154→
155→  const processedData = useMemo(() => {
156→    if (!enrichedTransaction) {
157→      return {
158→        cardTitle: '',
159→        formattedPointsValue: '',
160→        highlightText: '',
161→        formattedCurrencyValue: '',
162→        marketplaceContent: undefined,
163→        showOrderNumber: false,
164→        showStatus: false,
165→        showValue: false,
166→      };
167→    }
168→
169→    const gainType = getTransactionGainType(enrichedTransaction);
170→    const formattedCurrencyValue = formatToCurrency(
171→      enrichedTransaction.currencyValue,
172→    );
173→    const marketplaceValuePoints =
174→      enrichedTransaction?.marketplace?.valuePoints;
175→    const formattedPointsValue =
176→      marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
177→        ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
178→        : getFormattedPointsValue(
179→            enrichedTransaction.amount,
180→            enrichedTransaction.type,
181→          );
182→    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
183→    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
184→    const highlightText = getFormattedHighlightText(
185→      enrichedTransaction.date,
186→      gainType,
187→      moment,
188→    );
189→
190→    const isMarketplace = !!enrichedTransaction?.marketplace;
191→    const marketplace = enrichedTransaction?.marketplace;
192→
193→    let marketplaceContent: MarketplaceContentData | undefined;
194→    if (isMarketplace && marketplace) {
195→      const firstOrder = marketplace.orders?.[0];
196→      const firstPayment = marketplace.payments?.[0];
197→      const vendorName = firstOrder?.vendor || '';
198→
199→      const items: MarketplaceItemData[] = [];
200→      marketplace.orders?.forEach(order => {
201→        order.items?.forEach(item => {
202→          items.push({
203→            name: item.name,
204→            quantity: item.quantity,
205→            valuePoints: getFormattedPointsValueForMarketplace(
206→              item.valuePoints,
207→            ),
208→            imageUrl: item.imageUrl,
209→            cleanedImageUrl: getCleanedImageUrl(item.imageUrl),
210→          });
211→        });
212→      });
213→
214→      marketplaceContent = {
215→        orderNumber: enrichedTransaction.id,
216→        status: enrichedTransaction.status,
217→        statusColor: enrichedTransaction.status
218→          ? STATUS_COLORS[enrichedTransaction.status] || 'neutral'
219→          : undefined,
220→        paymentType: firstPayment
221→          ? getPaymentTypeLabel(firstPayment.paymentType)
222→          : undefined,
223→        shippingValuePoints:
224→          marketplace.shippingValuePoints !== undefined &&
225→          marketplace.shippingValuePoints !== null
226→            ? getFormattedPointsValueForMarketplace(
227→                marketplace.shippingValuePoints,
228→              )
229→            : undefined,
230→        valuePoints:
231→          marketplace.valuePoints !== undefined &&
232→          marketplace.valuePoints !== null
233→            ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
234→            : undefined,
235→        vendorName: vendorName || undefined,
236→        items,
237→      };
238→    }
239→
240→    return {
241→      cardTitle,
242→      formattedPointsValue,
243→      highlightText,
244→      formattedCurrencyValue,
245→      marketplaceContent,
246→      showOrderNumber: !isMarketplace,
247→      showStatus: !isMarketplace,
248→      showValue: !isMarketplace,
249→    };
250→    // eslint-disable-next-line react-hooks/exhaustive-deps
251→  }, [
252→    transaction,
253→    passedType,
254→    passedIcon,
255→    passedStatus,
256→    passedOrigination,
257→  ]);
258→
259→  return (
260→    <MyOrdersDetailView
261→      handleGoBack={handleGoBack}
262→      transaction={enrichedTransaction}
263→      modalizeRef={modalizeRef}
264→      modalizeRefInfo={modalizeRefInfo}
265→      handleOpenReportProblem={handleOpenReportProblem}
266→      handleCloseReportProblem={handleCloseReportProblem}
267→      handleOpenInfo={handleOpenInfo}
268→      handleCloseInfo={handleCloseInfo}
269→      isLoading={isLoading}
270→      hasError={hasError}
271→      handleRetry={handleRetry}
272→      isCashback={isCashback}
273→      cardTitle={processedData.cardTitle}
274→      formattedPointsValue={processedData.formattedPointsValue}
275→      highlightText={processedData.highlightText}
276→      formattedCurrencyValue={processedData.formattedCurrencyValue}
277→      marketplaceContent={processedData.marketplaceContent}
278→      showOrderNumber={processedData.showOrderNumber}
279→      showStatus={processedData.showStatus}
280→      showValue={processedData.showValue}
281→      height={height}
282→    />
283→  );
284→};
285→
286→export default MyOrdersDetails;
